import React, { useEffect, useState, useRef } from "react";
import { Trash2, Pencil, Plus, ChevronDown, Search } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { linkHomeDesign as design } from "../../design/linkHomeDesign";

const API = "http://localhost:5000/api/links";

const sortOptions = [
  { label: "Sort by Position", value: "order" },
  { label: "Sort by Name", value: "name" },
  { label: "Sort by Status", value: "status" },
];

const LinkHome = () => {
  const [links, setLinks] = useState([]);
  const [view, setView] = useState("home");
  const [sort, setSort] = useState("order");
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const [search, setSearch] = useState("");

  const dropdownRef = useRef(null);

  const [name, setName] = useState("");
  const [isActive, setIsActive] = useState(true);

  // Fetch only parent links
  const fetchLinks = async () => {
    const res = await fetch(API);
    const data = await res.json();
    setLinks(data.filter((l) => !l.parent));
  };

  useEffect(() => {
    fetchLinks();
  }, []);

  // Close dropdown outside click
  useEffect(() => {
    const handler = (e) => {
      if (!dropdownRef.current?.contains(e.target)) {
        setDropdownOpen(false);
      }
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  // Process links
  const processedLinks = [...links]
    .filter((l) =>
      l.name.toLowerCase().includes(search.toLowerCase())
    )
    .sort((a, b) => {
      if (sort === "name") return a.name.localeCompare(b.name);
      if (sort === "status") return b.isActive - a.isActive;
      return 0; // position auto from index
    });

  // Add new parent link
  const handleSubmit = async (e) => {
    e.preventDefault();

    await fetch(API, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        name,
        isActive,
        parent: null,
      }),
    });

    setName("");
    setIsActive(true);
    setView("home");
    fetchLinks();
  };

  return (
    <div className={design.pageWrapper}>
      <div className={design.container}>

        {/* HEADER */}
        <div className={design.header}>
          <h1 className={design.title}>Parent Navigation Links</h1>
          <p className={design.subtitle}>
            Manage only main menu navigation.
          </p>

          <div className={design.pathWrapper}>
            {view === "home" && (
              <span className={design.pathActive}>
                linkhome
              </span>
            )}

            {view === "add" && (
              <>
                <span
                  onClick={() => setView("home")}
                  className={design.path}
                >
                  linkhome
                </span>
                <span className={design.pathDivider}>/</span>
                <span className={design.pathActive}>
                  add-link
                </span>
              </>
            )}
          </div>
        </div>

        {/* NAVBAR */}
        {view === "home" && (
          <div className={design.navbar}>

            {/* Search */}
            <div className={design.searchWrapper}>
              <Search size={16} className="text-slate-400" />
              <input
                type="text"
                placeholder="Search link..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className={design.searchInput}
              />
            </div>

            <div className="flex items-center gap-4">

              {/* Dropdown */}
              <div className="relative" ref={dropdownRef}>
                <button
                  onClick={() => setDropdownOpen(!dropdownOpen)}
                  className={design.dropdownButton}
                >
                  {
                    sortOptions.find((o) => o.value === sort)?.label
                  }
                  <ChevronDown size={16} />
                </button>

                <AnimatePresence>
                  {dropdownOpen && (
                    <motion.div
                      initial={{ opacity: 0, y: -6 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0 }}
                      transition={{ duration: 0.2 }}
                      className={design.dropdownMenu}
                    >
                      {sortOptions.map((option) => (
                        <div
                          key={option.value}
                          onClick={() => {
                            setSort(option.value);
                            setDropdownOpen(false);
                          }}
                          className={`${design.dropdownItem} ${
                            sort === option.value
                              ? design.dropdownActive
                              : ""
                          }`}
                        >
                          {option.label}
                        </div>
                      ))}
                    </motion.div>
                  )}
                </AnimatePresence>
              </div>

              {/* Add Button */}
              <button
                onClick={() => setView("add")}
                className={design.addButton}
              >
                <Plus size={16} />
                Add Link
              </button>
            </div>
          </div>
        )}

        {/* TABLE */}
        {view === "home" && processedLinks.length > 0 && (
          <div className={design.table}>
            {processedLinks.map((link, index) => (
              <div key={link._id} className={design.row}>
                
                {/* Auto Position */}
                <div className="font-medium text-slate-500">
                  {index + 1}
                </div>

                <div>{link.name}</div>

                <div>
                  {link.isActive ? "Active" : "Inactive"}
                </div>

                <div className="flex justify-end gap-4">
                  <Pencil size={16} className="cursor-pointer" />
                  <Trash2 size={16} className="cursor-pointer text-red-500" />
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Empty State */}
        {view === "home" && processedLinks.length === 0 && (
          <div className="bg-white rounded-2xl border border-slate-200 shadow-md p-10 text-center text-slate-500">
            No parent links found.
          </div>
        )}

        {/* ADD FORM */}
        <AnimatePresence>
          {view === "add" && (
            <motion.form
              initial={{ opacity: 0, y: 15 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0 }}
              transition={{ duration: 0.25 }}
              onSubmit={handleSubmit}
              className={design.form}
            >
              <input
                type="text"
                placeholder="Link Name"
                value={name}
                onChange={(e) => setName(e.target.value)}
                className={design.input}
                required
              />

              <select
                value={isActive}
                onChange={(e) =>
                  setIsActive(e.target.value === "true")
                }
                className={design.input}
              >
                <option value="true">Active</option>
                <option value="false">Inactive</option>
              </select>

              <div className="flex gap-4">
                <button
                  type="submit"
                  className={design.submitButton}
                >
                  Create
                </button>

                <button
                  type="button"
                  onClick={() => setView("home")}
                  className={design.cancelButton}
                >
                  Cancel
                </button>
              </div>
            </motion.form>
          )}
        </AnimatePresence>

      </div>
    </div>
  );
};

export default LinkHome;
